// ── useIsMobile hook
const useIsMobile = () => {
  const [mob, setMob] = useState(false);
  useEffect(() => {
    const h = () => setMob(window.innerWidth < 768);
    window.addEventListener("resize", h);
    return () => window.removeEventListener("resize", h);
  }, []);
  return mob;
};

