function Index() {
  const [page,setPage]=useState("home");
  const render=()=>{
    switch(page){
      case "home":return <HomePage setPage={setPage}/>;
      case "projects":return <ProjectsPage setPage={setPage}/>;
      case "contact":return <ContactPage/>;
      case "pride":return <ProjectPage proj={PROJECTS.pride} setPage={setPage}/>;
      case "aerox":return <ProjectPage proj={PROJECTS.aerox} setPage={setPage}/>;
      case "regalia":return <ProjectPage proj={PROJECTS.regalia} setPage={setPage}/>;
      case "paradise":return <ProjectPage proj={PROJECTS.paradise} setPage={setPage}/>;
      default:return <HomePage setPage={setPage}/>;
    }
  };
  return (
    <div style={{minHeight:"100vh",background:C.black}}>
      <GS/>
      <Nav page={page} setPage={setPage}/>
      <FloatingCTA/>
      <main>{render()}</main>
      <Footer setPage={setPage}/>
    </div>
  );
}


export const Route = createFileRoute("/")({ component: Index });
